mapper.update:
update course_evaluation
set rating = #{rating}, content = #{content}, teacher_evaluation = #{teacherEvaluation}, evaluation_time = #{evaluationTime}
where student_id = #{studentId} and course_id = #{courseId}

mapper.select:
select * from course_evaluation
where course_id = #{courseId}
order by evaluation_time desc

select * from course_evaluation
where teacher_id = #{teacherId}
order by evaluation_time desc
